/// Load the `RuleSet` from the rules file if configured, or use defaults silently.
fn load_rule_set(config: &TrackerConfig) -> RuleSet {
    // Try to find a rules file next to the binary or at a conventional path.
    // If no file is found or it can't be parsed, fall back to default_rules silently.
    let candidates = [
        std::path::Path::new("productivity_rules.toml"),
        std::path::Path::new("rules.toml"),
    ];
    for path in &candidates {
        if path.exists() {
            if let Ok(rs) = RuleSet::from_file(path) {
                return rs;
            }
        }
    }
    // Use the default_status from config if available.
    let mut rs = RuleSet::default_rules();
    rs.default_status
        .clone_from(&config.productivity.default_status);
