/// Load the `RuleSet` from the rules file, searching several locations:
///
/// 1. Next to the running binary (works when launched via launchd)
/// 2. XDG config dir (`~/.config/activtrak/`)
/// 3. Current working directory (works during development)
///
/// Falls back to `default_rules` silently if no file is found.
fn load_rule_set(config: &TrackerConfig) -> RuleSet {
    let filenames = ["productivity_rules.toml", "rules.toml"];

    let mut candidates: Vec<std::path::PathBuf> = Vec::new();

    if let Ok(exe) = std::env::current_exe() {
        if let Some(dir) = exe.parent() {
            for name in &filenames {
                candidates.push(dir.join(name));
            }
        }
    }

    if let Some(dirs) = directories::BaseDirs::new() {
        let config_dir = dirs.config_dir().join("activtrak");
        for name in &filenames {
            candidates.push(config_dir.join(name));
        }
    }

    for name in &filenames {
        candidates.push(std::path::PathBuf::from(name));
    }

    for path in &candidates {
        if path.exists() {
            if let Ok(rs) = RuleSet::from_file(path) {
                return rs;
            }
        }
    }

    let mut rs = RuleSet::default_rules();
    rs.default_status
        .clone_from(&config.productivity.default_status);
    rs
}

/// Minimal activity row for re-classification at report time.
pub struct RawActivity {
    /// The executable name (e.g. "Ghostty").
    pub executable_name: String,
    /// The window title at the time of capture.
    pub window_title: String,
    /// The URL at the time of capture (empty string if none).
    pub url: String,
    /// Duration of the activity in seconds.
    pub duration_seconds: i64,
}

/// Return today's raw activity records for re-classification.
///
/// # Errors
///
/// Returns `TrackerError::Database` if the query fails.
pub fn get_raw_activity_today(conn: &Connection) -> Result<Vec<RawActivity>, TrackerError> {
    let mut stmt = conn.prepare(
        "SELECT executable_name, window_title, COALESCE(url, ''), duration_seconds
         FROM activity_log
         WHERE date(timestamp) = date('now')
         ORDER BY timestamp ASC",
    )?;
    let iter = stmt.query_map([], |row| {
        Ok(RawActivity {
            executable_name: row.get(0)?,
            window_title: row.get(1)?,
            url: row.get(2)?,
            duration_seconds: row.get(3)?,
        })
    })?;
    let mut results = Vec::new();
    for item in iter {
        results.push(item?);
    }
    Ok(results)
}

