/// Re-classify today's raw activity records using the current `RuleSet`.
///
/// Returns `(productive_secs, passive_secs, unproductive_secs, uncategorized_secs)`.
fn reclassify_today(conn: &rusqlite::Connection) -> (i64, i64, i64, i64) {
    let rule_set = load_report_rules();
    let records = db::get_raw_activity_today(conn).unwrap_or_default();

    let mut productive: i64 = 0;
    let mut passive: i64 = 0;
    let mut unproductive: i64 = 0;
    let mut uncategorized: i64 = 0;

    for r in &records {
        let url = if r.url.is_empty() {
            None
        } else {
            Some(r.url.as_str())
        };
        let status = rule_set.classify(&r.executable_name, &r.window_title, url);
        let lower = status.to_lowercase();
        if lower.contains("unproductive") {
            unproductive += r.duration_seconds;
        } else if lower.contains("productive") {
            productive += r.duration_seconds;
        } else if lower.contains("passive") {
            passive += r.duration_seconds;
        } else {
            uncategorized += r.duration_seconds;
        }
    }

    (productive, passive, unproductive, uncategorized)
}

/// Load the `RuleSet` using the same search strategy as the tracker.
fn load_report_rules() -> RuleSet {
    let filenames = ["productivity_rules.toml", "rules.toml"];
    let mut candidates: Vec<PathBuf> = Vec::new();

    if let Ok(exe) = std::env::current_exe() {
        if let Some(dir) = exe.parent() {
            for name in &filenames {
                candidates.push(dir.join(name));
            }
        }
    }

    if let Some(dirs) = BaseDirs::new() {
        let config_dir = dirs.config_dir().join("activtrak");
        for name in &filenames {
            candidates.push(config_dir.join(name));
        }
    }

    for name in &filenames {
        candidates.push(PathBuf::from(*name));
    }

    for path in &candidates {
        if path.exists() {
            if let Ok(rs) = RuleSet::from_file(path) {
                return rs;
            }
        }
    }

    RuleSet::default_rules()
}
